using System.ComponentModel.DataAnnotations;

namespace RecipeSharing.Models;

public class Recipe
{
    public int Id { get; set; }

    [Required, StringLength(100)]
    public string Title { get; set; } = string.Empty;

    [Required]
    public string Category { get; set; } = string.Empty;

    [Required]
    public string Ingredients { get; set; } = string.Empty;

    [Required]
    public string Steps { get; set; } = string.Empty;

    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

@page "/"
@inject RecipeSharing.Services.RecipeService RecipeService

<PageTitle>Recipe Sharing Community</PageTitle>

<h1>🍳 Recipe Sharing Community</h1>
<p class="lead">Discover and share delicious recipes from around the world.</p>

<h2 class="mt-4">Browse by Category</h2>
<div class="row mt-3">
    @foreach (var category in RecipeService.GetCategories())
    {
        <div class="col-md-4 mb-3">
            <div class="card h-100">
                <div class="card-body d-flex flex-column">
                    <h5 class="card-title">@GetCategoryIcon(category) @category</h5>
                    <p class="card-text text-muted">
                        @RecipeService.GetByCategory(category).Count recipe(s)
                    </p>
                    <a href="/recipes/@category" class="btn btn-outline-primary mt-auto">Browse</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private static string GetCategoryIcon(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Asian" => "🥢",
        "Mexican" => "🌮",
        "Desserts" => "🍰",
        _ => "🍽️"
    };
}

@page "/recipes/{Category}"
@inject RecipeSharing.Services.RecipeService RecipeService

<PageTitle>@Category Recipes</PageTitle>

<h1>@Category Recipes</h1>
<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@Category</li>
    </ol>
</nav>

@if (recipes.Count == 0)
{
    <p class="text-muted">No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        @if (recipe.RatingCount > 0)
                        {
                            <p class="card-text">
                                <span class="text-warning">@(new string('★', (int)Math.Round(recipe.AverageRating)))@(new string('☆', 5 - (int)Math.Round(recipe.AverageRating)))</span>
                                <small class="text-muted">(@recipe.RatingCount ratings)</small>
                            </p>
                        }
                        <a href="/recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string Category { get; set; } = string.Empty;

    private IReadOnlyList<RecipeSharing.Models.Recipe> recipes = [];

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetByCategory(Category);
    }
}

@page "/recipe/{Id:int}"
@inject RecipeSharing.Services.RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe")</PageTitle>

@if (recipe is null)
{
    <p class="text-danger">Recipe not found.</p>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/recipes/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@recipe.Category</span>

    <h3 class="mt-4">Ingredients</h3>
    <ul class="list-group list-group-flush mb-4">
        @foreach (var ingredient in recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            <li class="list-group-item">@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol class="list-group list-group-numbered mb-4">
        @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            var text = step.TrimStart();
            if (text.Length > 2 && text[0] >= '0' && text[0] <= '9' && text.Contains('.'))
                text = text[(text.IndexOf('.') + 1)..].TrimStart();
            <li class="list-group-item">@text</li>
        }
    </ol>

    <h3>Rate this Recipe</h3>
    <StarRating RecipeId="Id" />
}

@code {
    [Parameter]
    public int Id { get; set; }

    private RecipeSharing.Models.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@page "/submit"
@rendermode InteractiveServer
@inject RecipeSharing.Services.RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Thank you!</strong> Your recipe has been submitted successfully.
        <a href="/recipe/@submittedId">View your recipe</a>
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="model.Title" class="form-control" placeholder="e.g. Grandma's Apple Pie" />
            <ValidationMessage For="() => model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="model.Category" class="form-select">
                <option value="">-- Select a category --</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Asian">Asian</option>
                <option value="Mexican">Mexican</option>
                <option value="Desserts">Desserts</option>
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => model.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" @bind-Value="model.Ingredients" class="form-control" rows="6" placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
            <ValidationMessage For="() => model.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="model.Steps" class="form-control" rows="6" placeholder="1. Preheat oven to 350°F&#10;2. Mix dry ingredients&#10;3. Add wet ingredients" />
            <ValidationMessage For="() => model.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeSharing.Models.Recipe model = new();
    private bool submitted;
    private int submittedId;

    private void HandleSubmit()
    {
        RecipeService.AddRecipe(model);
        submittedId = model.Id;
        submitted = true;
    }
}

@rendermode InteractiveServer
@inject RecipeSharing.Services.RecipeService RecipeService

<div class="star-rating d-inline-flex align-items-center gap-2">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <button type="button"
                class="btn btn-link p-0 fs-3 text-decoration-none @(star <= selectedRating ? "text-warning" : "text-secondary")"
                @onclick="() => Rate(star)"
                aria-label="Rate @star stars">
            @(star <= selectedRating ? "★" : "☆")
        </button>
    }
    @if (hasRated)
    {
        <span class="text-success ms-2">Thanks! You rated @selectedRating star(s).</span>
    }
</div>

@if (recipe is not null && recipe.RatingCount > 0)
{
    <p class="mt-2 text-muted">
        Average: @recipe.AverageRating.ToString("F1") / 5 (@recipe.RatingCount ratings)
    </p>
}

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int selectedRating;
    private bool hasRated;
    private RecipeSharing.Models.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(RecipeId);
    }

    private void Rate(int stars)
    {
        selectedRating = stars;
        hasRated = true;
        RecipeService.AddRating(RecipeId, stars);
        recipe = RecipeService.GetById(RecipeId);
    }
}

