+    {
+        var star = i;
+        <button type="button"
+                class="btn btn-link p-0 fs-3 text-decoration-none @(star <= selectedRating ? "text-warning" : "text-secondary")"
+                @onclick="() => Rate(star)"
+                aria-label="Rate @star stars">
+            @(star <= selectedRating ? "★" : "☆")
+        </button>
+    }
+    @if (hasRated)
+    {
+        <span class="text-success ms-2">Thanks! You rated @selectedRating star(s).</span>
+    }
+</div>
+
+@if (recipe is not null && recipe.RatingCount > 0)
