@page "/"
@inject RecipeSharing.Services.RecipeService RecipeService

<PageTitle>Recipe Sharing Community</PageTitle>

<h1>🍳 Recipe Sharing Community</h1>
<p class="lead">Discover and share delicious recipes from around the world.</p>

<h2 class="mt-4">Browse by Category</h2>
<div class="row mt-3">
    @foreach (var category in RecipeService.GetCategories())
    {
        <div class="col-md-4 mb-3">
            <div class="card h-100">
                <div class="card-body d-flex flex-column">
                    <h5 class="card-title">@GetCategoryIcon(category) @category</h5>
                    <p class="card-text text-muted">
                        @RecipeService.GetByCategory(category).Count recipe(s)
                    </p>
                    <a href="/recipes/@category" class="btn btn-outline-primary mt-auto">Browse</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private static string GetCategoryIcon(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Asian" => "🥢",
        "Mexican" => "🌮",
        "Desserts" => "🍰",
        _ => "🍽️"
    };
}

